//! `baton-get` logic: read a data object's bytes back to the caller.
//!
//! Inline mode (default) emits the bytes as a raw JSON string on
//! the output JSON's `data` field. The bytes must be valid UTF-8;
//! non-UTF-8 input surfaces as `USER_INPUT_PATH_ERR` (-317000),
//! mirroring upstream baton's `read.c:116-135` behaviour. partisan
//! and extendo both consume the field as raw text â€” see #57
//! (Cluster D).
//!
//! `--save` file mode streams bytes directly to disk and skips the
//! inline `data` field. The local path follows upstream baton's
//! `json_to_local_path` priority (`baton/src/json.c:1211-1244`):
//!
//! 1. `<directory>/<file>` if both are present
//! 2. `<directory>/<data_object>` if `file` is absent
//! 3. `./<file>` if `directory` is absent but `file` is present
//! 4. `./<data_object>` if neither `directory` nor `file` is present
//!
//! Cases 3 / 4 default the parent to the process's cwd â€” same
//! fallback upstream uses when the caller omits `directory`.
//!
//! On the `--save` path bytes are written to a hidden sibling
//! (`<dir>/.<basename>.partial`) and only renamed onto the final
//! name once the read, fsync, *and* verify all pass. A failed get
//! therefore leaves no artefact at the destination â€” neither an
//! empty zero-byte file nor a partial download. See #65.

use std::io::Write;
use std::path::PathBuf;

use tempfile::NamedTempFile;

use crate::connection::{OpenMode, RodsConnection};
use crate::error::BatonError;
use crate::types::Target;

/// Caller-controlled flags for [`get_one`].
#[derive(Debug, Default, Clone, Copy)]
pub struct GetOptions {
    /// `--save` file mode. When `true`, [`get_one`] streams bytes from
    /// iRODS to a local file at the path resolved per the module
    /// doc-comment, and leaves the `data` field unset on the output.
    /// When `false`, the inline raw-UTF-8 path is used.
    pub save: bool,

    /// Compute MD5 client-side as bytes are read and compare against
    /// the catalog-recorded server checksum after the read completes.
    /// Mismatch surfaces as an in-band error. Symmetric with
    /// `PutOptions::verify`. Mirrors upstream baton-get's
    /// `--verify` flag (`baton/src/baton-get.c:78`) and partisan's
    /// `verify_checksum` argument on get
    /// (`partisan/src/partisan/irods.py:477`).
    pub verify: bool,

    /// Accepted on the wire for upstream-CLI compatibility but a
    /// no-op in baton-rs: the local-path write path uses
    /// `File::create`, which truncates an existing file
    /// unconditionally â€” the same behaviour upstream baton emits
    /// when `force` is set (it's the default on baton-get; opt out
    /// via `--no-clobber`). Both partisan and extendo send `force`
    /// to mean "overwrite if present"; this field accepts the wire
    /// shape so dispatchers don't drop it.
    pub force: bool,
}

// 64 KiB is a moderate compromise: small enough that the per-call
// memory cost is negligible for tiny files, large enough that the
// rcDataObjRead overhead doesn't dominate for objects that span
// multiple chunks. Same chunk size for inline and save paths so
// behaviour stays uniform; the save path additionally avoids the
// O(file size) memory cost of accumulating into a single Vec.
const READ_CHUNK_SIZE: usize = 64 * 1024;

/// Read a single data object end-to-end.
///
/// Inline mode (`opts.save == false`): bytes accumulated in memory,
/// base64-encoded, returned on the output `data` field.
///
/// Save mode (`opts.save == true`): bytes streamed to disk; `data`
/// left unset on the output. The local path is constructed per
/// upstream baton's `json_to_local_path` priority â€” see the module
/// doc-comment. Both `directory` and `file` are echoed unchanged on
/// the output when set on the input.
///
/// Collections are an error: there's nothing to download for a
/// collection in baton's data model. Upstream baton-get returns an
/// equivalent error, so we mirror that.
pub fn get_one(
    conn: &mut RodsConnection,
    target: Target,
    opts: &GetOptions,
) -> Result<Target, BatonError> {
    let path = target.path();
    let mut data_obj = match target {
        Target::DataObject(d) => d,
        Target::Collection(c) => {
            // -310000 USER_FILE_DOES_NOT_EXIST. Wire-shape align
            // with upstream baton; see audit on PR #80's thread.
            return Err(BatonError::from_irods_with_context(
                -310000,
                &format!(
                    "baton-get: target is a collection, not a data object: {}",
                    c.collection
                ),
            ));
        }
    };

    // Allocate a hashing context up front when --verify is requested
    // so the streaming path can update it in place chunk by chunk
    // rather than going back over the bytes afterwards. Symmetric
    // with the put-side --verify implementation in `operations::put`.
    let mut hash = if opts.verify {
        Some(md5::Context::new())
    } else {
        None
    };

    // The `--save` path uses a temp-then-rename pattern: write to a
    // hidden sibling, and only promote it to the final name once the
    // read, fsync, *and* verify all pass. Any early return between
    // here and the final rename leaves no artefact at the destination
    // (see #65). `NamedTempFile` removes the temp on Drop unless
    // `persist()` is called â€” so the cleanup guarantee spans the
    // verify step below for free.
    let mut pending: Option<(NamedTempFile, PathBuf)> = None;

    if opts.save {
        // Path priority mirrors `json_to_local_path` in
        // `baton/src/json.c:1211-1244`. `directory` defaults to "."
        // (the process cwd) and `file` is preferred over
        // `data_object` for the local basename. The directory must
        // exist on disk before the call â€” baton itself doesn't
        // auto-create.
        let directory = data_obj.directory.as_deref().unwrap_or(".");
        let basename = data_obj
            .file
            .as_deref()
            .unwrap_or(&data_obj.data_object);
        let mut local_path = PathBuf::from(directory);
        local_path.push(basename);

        // `tempfile_in(directory)` lands the temp on the same
        // filesystem as the destination â€” required for the eventual
        // `persist()` to be an atomic POSIX rename. The
        // `.<basename>.â€¦partial` naming keeps a partial download
        // identifiable on disk if something panics outside Drop
        // semantics (e.g. SIGKILL).
        let mut temp = tempfile::Builder::new()
            .prefix(&format!(".{}.", basename))
            .suffix(".partial")
            .tempfile_in(directory)
            .map_err(|e| {
                // -310000 USER_FILE_DOES_NOT_EXIST. Generalised
                // "local FS unhappy" code matching upstream baton's
                // local-side error mapping. Audit on PR #80's
                // thread.
                BatonError::from_irods_with_context(
                    -310000,
                    &format!(
                        "could not create local file {}: {}",
                        local_path.display(),
                        e
                    ),
                )
            })?;

        let handle = conn.open_data_object(&path, OpenMode::Read)?;
        let result = stream_to_writer(conn, handle, temp.as_file_mut(), hash.as_mut());
        let _ = conn.close_data_object(handle);
        result?;

        // Ensure bytes hit the OS before we declare success. Without
        // this, a concurrent reader (e.g. a downstream pipeline) could
        // see a short file when --save returns.
        temp.as_file().sync_all().map_err(|e| {
            // -310000 USER_FILE_DOES_NOT_EXIST â€” see above.
            BatonError::from_irods_with_context(
                -310000,
                &format!("flushing local file {}: {}", local_path.display(), e),
            )
        })?;

        pending = Some((temp, local_path));
    } else {
        let handle = conn.open_data_object(&path, OpenMode::Read)?;
        let read_result = read_to_end(conn, handle);
        // Best-effort close on both success and failure paths. A close
        // failure on the success path is logged-but-ignored: the bytes
        // are already in hand and there's nothing useful for the
        // caller to do with a stale L1 descriptor.
        let _ = conn.close_data_object(handle);
        let bytes = read_result?;
        if let Some(ctx) = hash.as_mut() {
            // Inline mode: hash the buffer all at once. The
            // streaming `consume` API matches the chunked save path
            // semantically, so the digest is identical regardless
            // of mode.
            ctx.consume(&bytes);
        }
        // Emit content as a raw JSON string, mirroring upstream
        // baton's `read.c:116-135`: it `json_pack("s", content)`s the
        // bytes verbatim and errors with `USER_INPUT_PATH_ERR` when
        // they're not UTF-8. partisan's `obj.read()`
        // (`partisan/src/partisan/irods.py:`) returns
        // `result[Baton.DATA]` directly and expects raw text â€” see
        // #57 (Cluster D).
        match String::from_utf8(bytes) {
            Ok(s) => {
                data_obj.data = Some(s);
            }
            Err(e) => {
                let len = e.as_bytes().len();
                return Err(BatonError {
                    // -317000 = USER_INPUT_PATH_ERR. Same code +
                    // message shape upstream emits when the bytes
                    // can't be JSON-encoded as UTF-8. Goes through
                    // `from_irods` so the prose-enrichment table in
                    // `error::descriptive_phrase` can tag it later
                    // if downstream consumers ever pin a phrase
                    // for this code.
                    code: -317000,
                    message: format!(
                        "the contents of '{}' cannot be encoded as UTF-8 \
                         for JSON output ({} bytes)",
                        path, len
                    ),
                });
            }
        }
    }

    if let Some(ctx) = hash {
        // Read the catalog-recorded checksum (no keywords â†’
        // catalog state, computing if missing) and compare against
        // the client-side hash we accumulated during the read.
        // Mirrors the post-put verify path in `operations::put`.
        let server_chksum = conn.checksum_data_object(&path, 0)?;
        let client_hex = format!("{:x}", ctx.finalize());
        super::verify_checksum(&client_hex, &server_chksum, "get")?;
    }

    // Final step on the save path: atomically promote the temp file
    // to its destination name. Any error above this point has
    // already short-circuited via `?` and `NamedTempFile`'s Drop
    // has removed the temp. `persist()` returns a `PersistError`
    // wrapping the temp file on failure; we let that drop here so
    // the temp is cleaned up even when the rename itself fails.
    // See #65.
    if let Some((temp, local_path)) = pending {
        temp.persist(&local_path).map_err(|e| {
            // -310000 USER_FILE_DOES_NOT_EXIST â€” local-FS error
            // family. Audit on PR #80's thread.
            BatonError::from_irods_with_context(
                -310000,
                &format!(
                    "renaming temp file to {}: {}",
                    local_path.display(),
                    e.error
                ),
            )
        })?;
    }

    Ok(Target::DataObject(data_obj))
}

/// Same as [`get_one`], but catches iRODS errors and emits the input
/// annotated with an `"error"` field instead of propagating. Mirrors
/// `list_one_annotated` and `metamod_one_annotated` so binaries can
/// keep their NDJSON loops uniform.
pub fn get_one_annotated(
    conn: &mut RodsConnection,
    target: Target,
    opts: &GetOptions,
) -> Target {
    super::annotate_failure(target, |t| get_one(conn, t, opts))
}

fn read_to_end(conn: &mut RodsConnection, handle: i32) -> Result<Vec<u8>, BatonError> {
    let mut buf = vec![0u8; READ_CHUNK_SIZE];
    let mut content = Vec::new();
    loop {
        let n = conn.read_data_object(handle, &mut buf)?;
        if n == 0 {
            break;
        }
        content.extend_from_slice(&buf[..n]);
    }
    Ok(content)
}

/// Stream the data object behind `handle` into `out`, chunk by chunk.
/// Used by the `--save` path to avoid accumulating the entire object
/// in memory before writing. When `hash` is `Some`, each chunk is
/// folded into the hashing context before being written, so a
/// post-stream `finalize()` matches the bytes that landed on disk
/// exactly.
fn stream_to_writer<W: Write>(
    conn: &mut RodsConnection,
    handle: i32,
    out: &mut W,
    mut hash: Option<&mut md5::Context>,
) -> Result<(), BatonError> {
    let mut buf = vec![0u8; READ_CHUNK_SIZE];
    loop {
        let n = conn.read_data_object(handle, &mut buf)?;
        if n == 0 {
            break;
        }
        if let Some(ref mut ctx) = hash {
            ctx.consume(&buf[..n]);
        }
        out.write_all(&buf[..n]).map_err(|e| {
            // -310000 USER_FILE_DOES_NOT_EXIST â€” local-FS error
            // family. Audit on PR #80's thread.
            BatonError::from_irods_with_context(
                -310000,
                &format!("writing local file: {}", e),
            )
        })?;
    }
    Ok(())
}
